def assess(record: dict) -> str:
    required = {'params', 'metric', 'case_id', 'seed', 'rerun_metric', 'tolerance'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get('seed') not in (None, False, 0, "", set(), [], {}):
        return 'PASS'
    return 'REJECT'

valid = {"case_id": 'CASO-SYN-1A', 'seed': True, 'params': True, 'metric': 'precision_at_k', 'rerun_metric': True, 'tolerance': True}
adverse = {"case_id": 'CASO-SYN-1A-ADV', 'seed': False, 'params': False, 'metric': 'precision_at_k', 'rerun_metric': False, 'tolerance': False}
missing = {k: valid[k] for k in valid if k != 'tolerance'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

